28	#pragma mark - register
29	+ (void)regiseterDigitalKeyRouters
30	{
31	    static dispatch_once_t onceToken;
32	    dispatch_once(&onceToken, ^{
33	        [self internalRegiseterDigitalKeyRouters];
34	    });
35	}
36	
37	+ (void)internalRegiseterDigitalKeyRouters {
38	    [XPRouter registerURLPattern:XPRouterURL_Digital_Key_Card_Auth_Cancel routerHandler:^(NSDictionary *params) {
39	        //DO NOTTHING.
40	        DLogTagDebug(kBLEKeyTag, @"处理非车主数字钥匙授权过期/被取消授权推送消息，目前没定义消息跳转");
41	    }];
42	    
43	    [XPRouter registerURLPattern:XPRouterURL_Digital_Key_Receive_Card routerHandler:^(NSDictionary *params) {
44	         dispatch_async(dispatch_get_main_queue(), ^{
45	             [self digitalKeyReceiveCard:params];
46	         });
47	     }];
48	    
49	    [XPRouter registerURLPattern:XPRouterURL_Digital_Key_Activate_Card routerHandler:^(NSDictionary *params) {
50	         dispatch_async(dispatch_get_main_queue(), ^{
51	             [self digitalKeyActiveCard:params];
52	         });
53	     }];
54	    
55	    [XPRouter registerURLPattern:XPRouterURL_Digital_Key_Card_Manager routerHandler:^(NSDictionary *params) {
56	         dispatch_async(dispatch_get_main_queue(), ^{
57	             [self digitalKeyOwnCardNotification:params];
58	         });
59	     }];
60	    
61	    [XPRouter registerURLPattern:XPRouterURL_Digital_Key_All_Card_List routerHandler:^(NSDictionary *params) {
62	         dispatch_async(dispatch_get_main_queue(), ^{
63	             [self digitalKeyAllCardList:params];
64	         });
65	     }];
66	    
67	    [XPRouter registerURLPattern:XPRouterURL_digital_key_generate_token routerHandler:^(NSDictionary *params) {
68	        dispatch_async(dispatch_get_main_queue(), ^{
69	            [self digitalKeyAllCardList:params];
70	        });
71	    }];
72	    
73	    [XPRouter registerURLPattern:XPRouterURL_digital_key_card_check routerHandler:^(NSDictionary *params) {
74	         dispatch_async(dispatch_get_main_queue(), ^{
75	             [self digitalKeyAllCardList:params];
76	         });
77	     }];
78	
79	    [XPRouter registerURLPattern:XPRouterURL_Digital_Key_Ble_Key_Check routerHandler:^(NSDictionary *routerParameters) {
80	        dispatch_async(dispatch_get_main_queue(), ^{
81	            [self digitalKeyBleKeyCheck:routerParameters];
82	        });
83	    }];
84	}
