86	/*
87	 车主发出钥匙授权消息
88	 车主变更有效期
89	 授权凭证失效提醒
90	 钥匙有效期到期提醒
91	 */
92	+ (void)digitalKeyReceiveCard:(NSDictionary*)params {
93	    __CHECK(CTMediator.isLogin)
94	    __CHECK(0!=CTMediator.defaultCarVin.length)
95	    NSString* vin = [params objectForKey:@"vin"];
96	    MyCarInfo* carInfo = [CTMediator carInfoForVin:vin];
97	    if(carInfo) {
98	        [CTMediator pickCarInfoAsDefaultCarInfo:carInfo];
99	        UIViewController *vc = [CTMediator createXPNewCarAuthorizedDetailViewController:@{@"vin":vin? : @""}];
100	        [UIViewController.currentFrontViewController safePushViewController:vc animated:YES];
101	    }
102	}
103	/*
104	钥匙激活成功
105	*/
106	+ (void)digitalKeyActiveCard:(NSDictionary*)params {
107	    __CHECK(CTMediator.isLogin)
108	    __CHECK(0!=CTMediator.defaultCarVin.length)
109	    NSString* vin = [params objectForKey:@"vin"];
110	    MyCarInfo* carInfo = [CTMediator carInfoForVin:vin];
111	    if(carInfo) {
112	        [CTMediator pickCarInfoAsDefaultCarInfo:carInfo];
113	        DLogTagInfo(kBLEKeyTag, @"carInfo存在，跳转到接收者钥匙页面");
114	        UIViewController *vc = [CTMediator createXPNewCarAuthorizedDetailViewController:@{@"vin":vin? : @""}];
115	        [UIViewController.currentFrontViewController safePushViewController:vc animated:YES];
116	    } else {
117	        DLogTagInfo(kBLEKeyTag, @"carInfo不存在，toast提示不拥有该车辆");
118	        [XPToast showMessage:@"该车辆的授权已被解除"];
119	    }
120	}
121	/*
122	 接受者删除钥匙
123	 授权钥匙过期
124	 钥匙到期提醒
125	 */
126	+ (void)digitalKeyOwnCardNotification:(NSDictionary*)params {
127	    __CHECK(CTMediator.isLogin)
128	    __CHECK(0!=CTMediator.defaultCarVin.length)
129	
130	    NSString* vin = [params objectForKey:@"vin"];
131	    MyCarInfo* carInfo = [CTMediator carInfoForVin:vin];
132	    if(carInfo) {
133	        const uint64_t uid = [[params objectForKey:@"uid"] longLongValue];
134	        UIViewController *vc = [CTMediator createWarrantyDetailViewController:@{@"vin":vin?:@"",
135	                                                                                @"uid":@(uid),}];
136	        [UIViewController.currentFrontViewController safePushViewController:vc animated:YES];
137	    }
138	}
