140	//数字钥匙管理界面
141	+ (void)digitalKeyAllCardList:(NSDictionary*)params {
142	    __CHECK(CTMediator.isLogin)
143	    __CHECK(0!=CTMediator.defaultCarVin.length)
144	    if(![CTMediator.defaultCarInfo isMyOwnerCar]) {
145	        DLogTagInfo(kBLEKeyTag, @"试驾员不能创建华米NFC钥匙");
146	        return;
147	    }
148	    
149	    if(![CTMediator isCurrentPageCreateWatchKeyPage]) {
150	        DLogTagInfo(kBLEKeyTag, @"当前页面不是创建华米钥匙页面");
151	        [CTMediator.tabBarController switchToTab:XPTabBarIndexCar];
152	        UIViewController *vc = [CTMediator createKeySettingViewController:@{}];
153	        if(![UIViewController.currentFrontViewController isKindOfClass:vc.class]) {
154	            DLogTagInfo(kBLEKeyTag, @"当前页面不是创建华米钥匙页面或钥匙管理页面，跳转到钥匙管理页面");
155	            [UIViewController.currentFrontViewController safePushViewController:vc animated:YES];
156	        }
157	    } else {
158	        DLogTagInfo(kBLEKeyTag, @"创建华米钥匙页面展示倒计时");
159	        [CTMediator showSeconds];
160	    }
161	}
162	
163	+ (void)digitalKeyBleKeyCheck:(NSDictionary *)params{
164	    XPCompletion completion = params[XPRouter_Completion];
165	    
166	    if(!CTMediator.isLogin){
167	        [XPToast showMessage:@"请先登录"];
168	        [CTMediator jumpToLoginWithCompletion:nil cancelAction:nil];
169	        if (completion) completion(nil);
170	        return;
171	    }
172	    
173	    if(CTMediator.defaultCarVin.length == 0){
174	        [XPToast showMessage:@"App未绑定车辆，请绑定后重试"];
175	        if (completion) completion(nil);
176	        return;
177	    }
178	
179	    NSString *vin = [params objectForKey:@"vin"];
180	    if(vin.length > 0 && ![vin isEqualToString:CTMediator.vin]){
181	        MyCarInfo *carInfo = [CTMediator carInfoForVin:vin];
182	        if(!carInfo){
183	            DLogTagInfo(kBLEKeyTag, @"carInfo不存在，toast提示不拥有该车辆");
184	            [XPToast showMessage:@"该车辆的授权已被解除"];
185	            if (completion) completion(nil);
186	            return;
187	        }
188	        DLogTagInfo(kBLEKeyTag, @"切换到指定车辆");
189	        [CTMediator pickCarInfoAsDefaultCarInfo:carInfo];
190	    }
191	    
192	    XPTabBarController *tabBarController = [CTMediator tabBarController];
193	    [tabBarController switchToTab:XPTabBarIndexCar];
194	    
195	    dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(0.3f * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
196	        
197	        MyCarInfo *carInfo = CTMediator.defaultCarInfo;
198	        if(!(carInfo.hasBleAbility && !carInfo.carFunction.WITHOUT_BLE)){
199	            DLogTagInfo(kBLEKeyTag, @"车辆不支持蓝牙钥匙");
200	            [XPToast showMessage:@"当前车辆不支持手机钥匙"];
201	            if (completion) completion(nil);
202	            return;
203	        }
204	        
205	        UIViewController *vc = [CTMediator createBleCheckViewController:@{@"command": @(1), @"skipAlert": @YES, @"from": @(1)}];
206	        
207	        if(![UIViewController.currentFrontViewController isKindOfClass:vc.class]) {
208	            DLogTagInfo(kBLEKeyTag, @"当前页面不是钥匙检查页面，跳转到钥匙检查页面");
209	            [UIViewController.currentFrontViewController safePushViewController:vc animated:YES];
210	        }else{
211	            DLogTagInfo(kBLEKeyTag, @"当前页面是钥匙检查页面，不跳转");
212	        }
213	        
214	        if (completion) completion(nil);
215	    });
216	}
